      "https://raw.githubusercontent.com/gbunmi/images/main/Penuel%20-%20Skills.png",
      "https://raw.githubusercontent.com/gbunmi/images/main/Penuel%20-%20Footer.png",
    ],
    links: [
      { label: "Visit Website ↗", url: "https://penueldev.onrender.com/" }
    ],
    overview: "" 
  },

  "Chinwe Ekeke": {
    description: "A virtual assistant portfolio built in Framer, showcasing skills, services, and client interactions to highlight professionalism and efficiency.",
    images: [
      "https://raw.githubusercontent.com/gbunmi/images/main/Chinwe%20-%20Hero.png",
      "https://raw.githubusercontent.com/gbunmi/images/main/Chinwe%20-%20About.png",
      "https://raw.githubusercontent.com/gbunmi/images/main/Chinwe%20Skills.png",
      "https://raw.githubusercontent.com/gbunmi/images/main/Chinwe%20-%20Case%20study.png",
      "https://raw.githubusercontent.com/gbunmi/images/main/Chinwe%20-%20Toolkit.png",
      "https://raw.githubusercontent.com/gbunmi/images/main/Chinwe%20-%20Footer.png",
    ],
    links: [
      { label: "Visit Website ↗", url: "https://chinweekeke.framer.website/" }
    ],
    overview: ""
  }
};

const DEFAULT_CONTENT: ProjectContent = {
  description: "Project description coming soon.",
  links: [],
  overview: "Detailed overview coming soon."
};

const FeaturedWorkView: React.FC = () => {
  const [selectedProject, setSelectedProject] = useState(PROJECTS[0]);
  const [mobileView, setMobileView] = useState<'list' | 'detail'>('list');
  const [isLoading, setIsLoading] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);

  // Scroll to top and handle loading state when selectedProject changes
  useEffect(() => {
    setIsLoading(true);

    if (contentRef.current) {
        contentRef.current.scrollTop = 0;
    }
    // Ensure mobile browser also resets if layout allows
    window.scrollTo(0, 0);

    const content = PROJECT_DATA[selectedProject] || DEFAULT_CONTENT;

    // Collect all images to preload
    const imagesToLoad: string[] = [...(content.images || [])];

    // Extract images from sections
    content.sections?.forEach(section => {
        const matches = section.body.match(/\{\{IMAGE:(.*?)\}\}/g);
        if (matches) {
            matches.forEach(match => {
                const url = match.replace('{{IMAGE:', '').replace('}}', '');
                imagesToLoad.push(url);
            });
        }
    });

    if (imagesToLoad.length === 0) {
        // Minimal delay for smooth transition even without images
        const timer = setTimeout(() => setIsLoading(false), 300);
        return () => clearTimeout(timer);
    }

    let loadedCount = 0;
    let isMounted = true;

    const checkAllLoaded = () => {
        if (!isMounted) return;
        loadedCount++;
        if (loadedCount >= imagesToLoad.length) {
            setIsLoading(false);
        }
    };

    imagesToLoad.forEach(src => {
        const img = new Image();
        img.src = src;
        img.onload = checkAllLoaded;
        img.onerror = checkAllLoaded;
    });

    // Fallback safety timeout (2s)
    const safetyTimer = setTimeout(() => {
        if (isMounted) setIsLoading(false);
    }, 2000);

    return () => {
        isMounted = false;
        clearTimeout(safetyTimer);
    };
  }, [selectedProject]);

  const content = PROJECT_DATA[selectedProject] || DEFAULT_CONTENT;

  const handleProjectClick = (project: string) => {
    if (project === selectedProject) return;
    setSelectedProject(project);
    setMobileView('detail');
  };

  return (
    <div className="h-full w-full bg-[#F8F5F0] flex flex-col md:flex-row overflow-hidden">

      {/* Left Sidebar - Project List */}
      <div 
        className={`
          w-full md:w-[300px] shrink-0 h-full overflow-y-auto border-b md:border-b-0 md:border-r border-[#DEDBD6] bg-[#F8F5F0] [&::-webkit-scrollbar]:hidden
          ${mobileView === 'detail' ? 'hidden md:block' : 'block'}
        `}
        style={{ scrollbarWidth: 'none' }}
      >
        {PROJECTS.map((project) => {
          const isSelected = selectedProject === project;
          return (
            <button
              key={project}
              onClick={() => handleProjectClick(project)}
              className={`
                group
                w-full text-left px-6 py-6 md:px-8 md:py-6 border-b border-[#DEDBD6] 
                font-bold text-sm md:text-base transition-colors
                ${isSelected 
                  ? 'bg-[#041727] text-white' 
                  : 'bg-[#F8F5F0] text-[#041727] hover:bg-[#ecece8]'}
              `}
            >
              <span className="inline-block transform transition-transform duration-300 group-hover:translate-x-2 tracking-[-0.04em]">
                {project}
              </span>
            </button>
          );
        })}
        {/* Fill remaining height on desktop to avoid empty space looking weird */}
        <div className="hidden md:block h-full bg-[#F8F5F0]" />
      </div>

      {/* Right Content - Project Details */}
      <div 
        ref={contentRef}
        className={`
          flex-1 h-full overflow-y-auto bg-[#F8F5F0] relative
          ${mobileView === 'list' ? 'hidden md:block' : 'block'}
        `}
      >

        {/* Content Container - Centered and Full Width with reduced padding */}
        <div className="px-6 py-8 md:px-20 xl:px-32 w-full mx-auto min-h-full">

          {/* Mobile Back Button */}
          <button 
            onClick={() => setMobileView('list')}
            className="md:hidden mb-8 flex items-center gap-2 text-sm font-bold text-[#041727] hover:opacity-70 tracking-[-0.04em]"
          >
            ← Back to Projects
          </button>

          {isLoading ? (
             <div className="flex items-center justify-center w-full h-[calc(100vh-10rem)]">
                <div className="w-8 h-8 border-4 border-[#DEDBD6] border-t-[#041727] rounded-full animate-spin"></div>
             </div>
          ) : (
            <div>
                {/* Header */}
                <div className="flex flex-col md:flex-row md:items-start justify-between gap-6 mb-4 md:mb-1 w-full">
                    <h1 className="text-3xl md:text-4xl font-bold text-[#041727] tracking-[-0.04em]">
                    {selectedProject}
                    </h1>

                    <div className="flex flex-wrap gap-3 shrink-0">
                    {content.links?.map((link, idx) => (
                        <a 
                        key={idx}
                        href={link.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="bg-[#041727] text-white px-3 py-1 text-xs md:text-sm font-bold hover:opacity-80 transition-opacity tracking-[-0.04em]"
                        >
                        {link.label}
                        </a>
                    ))}
                    </div>
                </div>

                {/* Description */}
                <p className="text-sm md:text-base text-[#041727] font-medium leading-relaxed mb-4 md:mb-6 w-full text-justify tracking-[-0.04em]">
                    {content.description}
                </p>

                {/* Images Container */}
                <div className="w-full mb-12">
                    {content.images && content.images.length > 0 ? (
                        content.images.map((imgSrc, index) => (
                        <img 
                            key={index}
                            src={imgSrc} 
                            alt={`${selectedProject} preview ${index + 1}`} 
                            className="w-full h-auto object-cover border border-[#DEDBD6] mb-12 last:mb-0"
                            loading="eager"
                            // @ts-ignore
                            fetchPriority="high"
                        />
                        ))
                    ) : (
                       null 
                    )}
                     {(!content.images || content.images.length === 0) && !content.sections && (
                         <div className="w-full aspect-video bg-[#ecece8] flex items-center justify-center text-gray-400 font-sans text-sm">
                            No images available
                         </div>
                     )}
                </div>

                {/* Structured Sections */}
                {content.sections && content.sections.map((section, idx) => (
                    <div key={idx} className="mb-12 w-full">
                    <span className="inline-block bg-[#041727] text-white px-1 py-0.5 text-sm font-bold mb-4 tracking-[-0.04em]">
                        {section.title}
                    </span>
                    <div className="text-sm md:text-base text-[#041727] font-medium leading-relaxed w-full text-justify tracking-[-0.04em]">
                        {section.body.split('\n').map((line, i) => {
                        const imageMatch = line.match(/^\{\{IMAGE:(.*)\}\}$/);
                        if (imageMatch) {
                            return (
                                <img 
                                    key={i}
                                    src={imageMatch[1]} 
                                    alt={`Detail ${i}`}
                                    className="w-full h-auto object-cover my-8 border border-[#DEDBD6]"
                                />
                            );
                        }
                        const isNumberedHeader = /^\d+\.\s/.test(line);
                        if (isNumberedHeader) {
                            return (
                            <div key={i} className="text-[#465460] font-bold mt-6 mb-2 text-left tracking-[-0.04em]">
                                {line}
                            </div>
                            );
                        }
                        if (line.trim() === '') return <br key={i} />;
                        return <div key={i}>{line}</div>;
                        })}
                    </div>
                    </div>
                ))}

                {/* Fallback Overview */}
                {!content.sections && content.overview && (
                    <div className="mb-12 w-full">
                    <span className="inline-block bg-[#041727] text-white px-1 py-0.5 text-sm font-bold mb-4 tracking-[-0.04em]">
                        Overview
                    </span>
                    <p className="text-sm md:text-base text-[#041727] font-medium leading-relaxed w-full text-justify tracking-[-0.04em]">
                        {content.overview}
                    </p>
                    </div>
                )}
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default FeaturedWorkView;
